import{bV as e,aL as l,u as n,G as r}from"./chunks/framework.BfzMay2U.js";const o=JSON.parse('{"title":"MySQL事务并发问题","description":"","frontmatter":{"title":"MySQL事务并发问题","date":"2021-11-28T19:29:15.000Z","categories":["Note"],"tags":["MySQL","dtm"]},"headers":[],"relativePath":"posts/mysql-dtm.md","filePath":"posts/mysql-dtm.md"}'),d={name:"posts/mysql-dtm.md"};function a(s,t,i,c,y,x){return l(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="mysql事务并发问题" tabindex="-1">MySQL事务并发问题 <a class="header-anchor" href="#mysql事务并发问题" aria-label="Permalink to &quot;MySQL事务并发问题&quot;">​</a></h1><h2 id="脏读-dirty-read" tabindex="-1">脏读(Dirty read) <a class="header-anchor" href="#脏读-dirty-read" aria-label="Permalink to &quot;脏读(Dirty read)&quot;">​</a></h2><blockquote><p>当一个事务正在访问的数据并且对数据进行了修改 ，而这种修改还没有提交到数据库中，这时另外一个事务也访问了这个数据，然后使用了这个数据。因为这个数据是还没提交的数据，那么另外一个事务读取到的这个数据是&quot;脏数据&quot;，依据&quot;脏数据&quot;所做的操作可能是不正确的。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:center;">时间点</th><th style="text-align:center;">事务 A</th><th style="text-align:center;">事务 B</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:center;">开启事务 A</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">2</td><td style="text-align:center;"></td><td style="text-align:center;">开启事务 B</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:center;">查询余额为 100</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">4</td><td style="text-align:center;"></td><td style="text-align:center;">余额增加至 150(尚未提交)</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:center;">查询余额为 150(脏数据)</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">6</td><td style="text-align:center;"></td><td style="text-align:center;">事务回滚</td></tr></tbody></table><h2 id="不可重复读-unrepeatableread" tabindex="-1">不可重复读(Unrepeatableread) <a class="header-anchor" href="#不可重复读-unrepeatableread" aria-label="Permalink to &quot;不可重复读(Unrepeatableread)&quot;">​</a></h2><blockquote><p>指在一个事务内多次读取同一数据。在这个事务还未结束时，另一个事务也访问该数据，那么，在第一个事务中的两次读数据之间，由于第二个事务的修改导致第一个事务两次读取的数据可能不太一样。这就发生了在一个事务内两次读到的数据是不一样的。因此成为不可重复读。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:center;">时间点</th><th style="text-align:center;">事务 A</th><th style="text-align:center;">事务 B</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:center;">开启事务 A</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">2</td><td style="text-align:center;"></td><td style="text-align:center;">开启事务 B</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:center;">查询余额为 100</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">4</td><td style="text-align:center;"></td><td style="text-align:center;">余额增加至 150</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:center;">查询余额为 100</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">6</td><td style="text-align:center;"></td><td style="text-align:center;">提交事务</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:center;">查询余额为 150</td><td style="text-align:center;"></td></tr></tbody></table><p><strong>体现在数据的修改，锁住一行记录即可</strong></p><h2 id="幻读-phantom-read" tabindex="-1">幻读(Phantom read) <a class="header-anchor" href="#幻读-phantom-read" aria-label="Permalink to &quot;幻读(Phantom read)&quot;">​</a></h2><blockquote><p>幻读与不可重复度类似，它发生在一个事务(T1)读取了几行数据，接着另外一个并发事务(T2)插入了一些数据时，在随后的查询中，第一个事务(T1)就会发现多了一些原本不存在的记录，就像发生了幻觉一样，所以称之为<strong>幻读</strong>。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:center;">时间点</th><th style="text-align:center;">事务 A</th><th style="text-align:center;">事务 B</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:center;">开启事务 A</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">2</td><td style="text-align:center;"></td><td style="text-align:center;">开启事务 B</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:center;">查询 id&lt;3 的所有记录，共 3 条</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;">4</td><td style="text-align:center;"></td><td style="text-align:center;">插入一条记录 id=2</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:center;"></td><td style="text-align:center;">提交事务</td></tr><tr><td style="text-align:center;">6</td><td style="text-align:center;">查询 id&lt;3 的所有记录，共 4 条</td><td style="text-align:center;"></td></tr></tbody></table><p><strong>体现在新增和删除，得锁住整张表</strong></p>',12)])])}const h=e(d,[["render",a]]);export{o as __pageData,h as default};
